/**
 * Generated i18n key enum where every member maps to a string equal to
 * its own name. The `$` separator nests the key namespace; both name and
 * value are pure identifier-shaped tokens, not credentials. The
 * hardcoded-secret rule must recognise this self-referential identifier
 * shape.
 *
 * Mirrors OpenHands' frontend/src/i18n/declaration.ts:796.
 */

export const I18N_KEYS = {
  BITBUCKET_DATA_CENTER$CONNECT_TO_BITBUCKET_DATA_CENTER: 'BITBUCKET_DATA_CENTER$CONNECT_TO_BITBUCKET_DATA_CENTER',
  GITHUB$CONNECT_TO_GITHUB: 'GITHUB$CONNECT_TO_GITHUB',
  GITLAB$CONNECT_TO_GITLAB: 'GITLAB$CONNECT_TO_GITLAB',
} as const;
